import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Customer Portal","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/customer-portal.md","filePath":"advanced/customer-portal.md"}'),n={name:"advanced/customer-portal.md"};function r(l,e,s,c,u,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="customer-portal" tabindex="-1">Customer Portal <a class="header-anchor" href="#customer-portal" aria-label="Permalink to &quot;Customer Portal&quot;">​</a></h1><p>The customer portal lets your clients view and pay invoices online through a secure, branded interface.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>When you send an invoice, a unique <strong>payment link</strong> is generated. When your customer clicks this link, they&#39;re taken to the customer portal where they can:</p><ol><li><strong>View the invoice</strong> — See all details, line items, and totals</li><li><strong>Download the PDF</strong> — Get a copy of the invoice</li><li><strong>Pay online</strong> — Complete payment through the portal</li><li><strong>Confirm payment</strong> — Acknowledge a bank transfer</li></ol><h2 id="portal-features" tabindex="-1">Portal features <a class="header-anchor" href="#portal-features" aria-label="Permalink to &quot;Portal features&quot;">​</a></h2><h3 id="invoice-view" tabindex="-1">Invoice view <a class="header-anchor" href="#invoice-view" aria-label="Permalink to &quot;Invoice view&quot;">​</a></h3><p>The portal shows a clean, branded view of the invoice including:</p><ul><li>Your company logo and branding</li><li>Invoice number and date</li><li>Line items with descriptions and amounts</li><li>VAT breakdown</li><li>Total amount due</li><li>Due date</li></ul><h3 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-label="Permalink to &quot;Payment&quot;">​</a></h3><p>Customers can pay directly through the portal. When payment is confirmed, the invoice status in your dashboard automatically updates to <strong>Paid</strong>.</p><h3 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h3><p>The customer portal uses your company branding:</p><ul><li>Company logo</li><li>Accent color</li><li>Company information</li></ul><p>This creates a professional, consistent experience for your customers.</p><h2 id="access-security" tabindex="-1">Access security <a class="header-anchor" href="#access-security" aria-label="Permalink to &quot;Access security&quot;">​</a></h2><p>Each portal link is:</p><ul><li><strong>Unique</strong> — Generated per invoice</li><li><strong>Token-based</strong> — Secured with a unique access token</li><li><strong>Invoice-specific</strong> — Only shows the specific invoice</li></ul><p>Customers don&#39;t need a MyCompanyDesk account to view and pay invoices.</p><h2 id="customer-event-tracking" tabindex="-1">Customer event tracking <a class="header-anchor" href="#customer-event-tracking" aria-label="Permalink to &quot;Customer event tracking&quot;">​</a></h2><p>MyCompanyDesk tracks customer interactions with the portal:</p><ul><li>When the customer opens the invoice</li><li>When they download the PDF</li><li>When they initiate payment</li><li>When payment is confirmed</li></ul><p>This helps you understand customer engagement and follow up effectively.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Include a personal note in your invoice email to encourage portal use</li><li>The portal works on all devices — mobile, tablet, and desktop</li><li>Payment confirmations are sent to both you and the customer</li><li>Check the customer event history on the invoice detail page to see portal interactions</li></ul>',25)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
